import { prisma } from "../../lib/prisma";

const getAllUsers = async () => {
    const result = await prisma.user.findMany({
        orderBy: {
            createdAt: "desc"
        }
    })
    return result
}

const getAllOrders = async () => {
    const result = await prisma.order.findMany({
        orderBy: {
            createdAt: "desc"
        }
    })
    return result
}


const toggleBanUser = async (userId: string) => {
  const existingUser = await prisma.user.findUnique({
    where: { id: userId },
  });

  if (!existingUser) {
    throw new Error("User not found");
  }

  // Prevent banning admin
  if (existingUser.role === "ADMIN") {
    throw new Error("Admin users cannot be banned");
  }

  const result = await prisma.user.update({
    where: { id: userId },
    data: {
      isBanned: !existingUser.isBanned,
    },
  });

  return result;
};

const getAllReviews = async()=>{
    const result = await prisma.review.findMany({
        orderBy:{
            createdAt:"desc"
        }
    })
    return result
}

const deleteReview= async(deleteId:string)=>{
    // console.log("Delete User",deleteId)
    const result = await prisma.review.delete({
        where:{
            id:deleteId
        }
    })
    return result
}

const deleteOrder= async(deleteId:string)=>{
    // console.log("Delete User",deleteId)
    const result = await prisma.order.delete({
        where:{
            id:deleteId
        }
    })
    return result
}





export const adminService = {
    getAllUsers,
    getAllOrders,
    toggleBanUser,
    getAllReviews,
    deleteReview,
    deleteOrder
};