import { Medicine } from "../../generated/prisma/client";
import { prisma } from "../../lib/prisma"


const createMedicine = async (data: {
    name: string;
    description: string;
    price: number; // because Decimal
    stock: number;
    manufacturer: string;
    imageURL?: string;
    categoryId: string;

}, sellerId: string) => {

    const category = await prisma.category.findUnique({
        where: { id: data.categoryId }
    })
    if (!category) {
        throw new Error("Category not found")
    }
    const result = await prisma.medicine.create({
        data: {
            ...data,
            sellerId
        }
    })
    return result
}

const getAllMedicine = async (payload: {
    search: string | undefined,
    category: string | undefined,
    manufacturer: string | undefined,
    price: number | undefined,
    minPrice: number | undefined,
    maxPrice: number | undefined,
    page: number,
    limit: number,
    skip: number,


}) => {
    const whereCondition: any = {};


    if (payload.search) {
        whereCondition.OR = [
            {
                name: {
                    contains: payload.search,
                    mode: "insensitive",
                },
            },
            {
                description: {
                    contains: payload.search,
                    mode: "insensitive",
                },
            },
            {
                manufacturer: {
                    contains: payload.search,
                    mode: "insensitive",
                },
            },
        ];
    }

    // if (payload.price !== undefined) {
    //     whereCondition.price = {
    //         equals: payload.price
    //     }
    // }

    // if (payload.minPrice !== undefined || payload.maxPrice !== undefined) {
    //     whereCondition.price = {
    //         gte: payload.minPrice,
    //         lte: payload.maxPrice
    //     };
    // }


    //     if (payload.minPrice !== undefined || payload.maxPrice !== undefined) {
    //   whereCondition.price = {}

    //   if (payload.minPrice !== undefined) {
    //     whereCondition.price.gte = payload.minPrice
    //   }

    //   if (payload.maxPrice !== undefined) {
    //     whereCondition.price.lte = payload.maxPrice
    //   }
    // }

//     if (payload.minPrice !== undefined ||payload.maxPrice !== undefined) {
//     whereCondition.price = {};

//     if (payload.minPrice !== undefined) {
//       whereCondition.price.gte = payload.minPrice;
//     }

//     if (payload.maxPrice !== undefined) {
//       whereCondition.price.lte = payload.maxPrice;
//     }
//   } else if (payload.price !== undefined) {
//     whereCondition.price = {
//       equals: payload.price,
//     };
//   }


    if (payload.category) {
        whereCondition.category = {
            name: {
                equals: payload.category,
                mode: "insensitive",
            },
        };
    }

    if (payload.manufacturer) {
        whereCondition.manufacturer = {
            contains: payload.manufacturer,
            mode: "insensitive",
        }
    }

    const total = await prisma.medicine.count({
        where: whereCondition
    })

    const result = await prisma.medicine.findMany({

        where: whereCondition,
        skip: payload.skip,
        take: payload.limit,
        include: {
            category: true,
        },
    });
    // return result;
    return {

        pagination: {
            page: payload.page,
            limit: payload.limit,
            total,
            totalPage: Math.ceil(total / payload.limit)

        },
        data: result
    }
}

const getMedicineById = async (medicineId: string) => {
    const result = await prisma.medicine.findUnique({
        where: {
            id: medicineId
        },
        include: {
            category: true,
            seller: {
                select: {
                    id: true,
                    name: true,
                }
            },
            reviews: true
        }
    })
    return result
}

const updateMedicineById = async (medicineId: string, sellerId: string, data: Partial<Medicine>) => {
    const existing = await prisma.medicine.findFirst({
        where: {
            id: medicineId,
            sellerId: sellerId
        }
    })

    if (!existing) {
        throw new Error("Not authorized or medicine not found")
    }

    const result = await prisma.medicine.update({
        where: {
            id: medicineId
        },
        data
    })
    return result
}




const deleteMedicineById = async (medicineId: string) => {
    // console.log("delete medicine")
    const result = await prisma.medicine.delete({
        where: {
            id: medicineId
        }

    })
    return result
}


export const medicineService = {
    createMedicine,
    getAllMedicine,
    getMedicineById,
    updateMedicineById,
    deleteMedicineById
}